// ─── Products ────────────────────────────────────────────────────────
export interface ProductSeed {
  id?: string
  name?: string
  slug?: string
  price?: string
  price_before?: string | null
  image_url?: string | null
  brand?: string
  category?: string
  stock?: number
  is_new?: boolean
  featured?: boolean
  description?: string
  specs?: string
  weight?: string
  variants?: any[] | null
}

export const DEFAULT_PRODUCT: Required<ProductSeed> = {
  id: "prod-001",
  name: "Bolsa de dormir camuflayado",
  slug: "bolsa-de-dormir-camuflayado",
  price: "Gs. 180.000",
